import{_ as o,o as i,c as e,a2 as l}from"./chunks/framework.BFVZdVmd.js";const u=JSON.parse('{"title":"Spring Cloud","description":"","frontmatter":{},"headers":[],"relativePath":"framework/spring-cloud.md","filePath":"framework/spring-cloud.md","lastUpdated":null}'),r={name:"framework/spring-cloud.md"};function n(t,a,s,d,p,c){return i(),e("div",null,[...a[0]||(a[0]=[l('<h1 id="spring-cloud" tabindex="-1">Spring Cloud <a class="header-anchor" href="#spring-cloud" aria-label="Permalink to &quot;Spring Cloud&quot;">​</a></h1><h2 id="是什么" tabindex="-1">是什么 <a class="header-anchor" href="#是什么" aria-label="Permalink to &quot;是什么&quot;">​</a></h2><p>Spring Cloud 是微服务治理框架，负责服务发现、服务调用、网关、负载均衡、熔断限流等微服务能力。微服务项目常用。</p><h2 id="spring-cloud-alibaba" tabindex="-1">Spring Cloud Alibaba <a class="header-anchor" href="#spring-cloud-alibaba" aria-label="Permalink to &quot;Spring Cloud Alibaba&quot;">​</a></h2><p><code>Spring Cloud Alibaba</code> 是国内项目常用的一套微服务组件集成，是 Spring Cloud 的扩展，整合了以下组件：</p><ul><li><strong>Nacos</strong>：注册中心和配置中心。</li><li><strong>Sentinel</strong>：限流熔断降级。</li><li><strong>RocketMQ</strong>：消息队列。</li><li><strong>Seata</strong>：分布式事务。</li></ul><h2 id="三者关系" tabindex="-1">三者关系 <a class="header-anchor" href="#三者关系" aria-label="Permalink to &quot;三者关系&quot;">​</a></h2><ul><li><strong>Spring Boot</strong>：基础，每个微服务本质上都是一个 Spring Boot 应用。</li><li><strong>Spring Cloud</strong>：微服务治理能力，例如服务注册、远程调用、网关、熔断限流。</li><li><strong>Spring Cloud Alibaba</strong>：国内项目常用的微服务组件集成，常配合 Nacos、Sentinel、RocketMQ、Seata 使用。</li></ul><h2 id="选型建议" tabindex="-1">选型建议 <a class="header-anchor" href="#选型建议" aria-label="Permalink to &quot;选型建议&quot;">​</a></h2><p>国内新项目通常采用：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Spring Boot 3.x + Spring Cloud 202x.x + Spring Cloud Alibaba</span></span></code></pre></div><p>以这套为底座，再按需引入 Nacos、Gateway、OpenFeign、Sentinel 等组件。</p>',12)])])}const h=o(r,[["render",n]]);export{u as __pageData,h as default};
